import {create} from "zustand";
import {persist} from "zustand/middleware";

interface ClppSettingsState {
  experimentalMode: boolean;
  defaultSchemaId: string | null;
  setExperimentalMode: (mode: boolean) => void;
  setDefaultSchemaId: (id: string | null) => void;
  reset: () => void;
}

const initialState = {
  experimentalMode: false,
  defaultSchemaId: null,
};

export const useClppSettingsStore = create<ClppSettingsState>()(
  persist(
    (set) => ({
      ...initialState,
      setExperimentalMode: (mode) => set({experimentalMode: mode}),
      setDefaultSchemaId: (id) => set({defaultSchemaId: id}),
      reset: () => set(initialState),
    }),
    {name: "clpp-settings"},
  ),
);

import {Card, CardContent, CardHeader, CardTitle} from "@/components/ui/card";
import {Label} from "@/components/ui/label";
import {Separator} from "@/components/ui/separator";
import {Switch} from "@/components/ui/switch";

import {useClppSettingsStore} from "@/features/clpp/stores/clpp-settings-store";


const SettingsPage = () => {
  const experimentalMode = useClppSettingsStore((s) => s.experimentalMode);
  const setExperimentalMode = useClppSettingsStore((s) => s.setExperimentalMode);

  return (
    <div className="mx-auto max-w-2xl p-6">
      <Card>
        <CardHeader>
          <CardTitle>Settings</CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="space-y-2">
            <h3 className="text-sm font-medium">General</h3>
            <Separator/>
            <div className="flex items-center gap-3 pt-2">
              <Switch
                checked={experimentalMode}
                onCheckedChange={setExperimentalMode}/>
              <Label>Experimental Mode</Label>
            </div>
          </div>
          <div className="space-y-2">
            <h3 className="text-sm font-medium">Schema Library</h3>
            <Separator/>
            <div className="pt-2">
              {/* TODO: Schema library component */}
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
};


export default SettingsPage;

